async function execute(api, params) {
    const results = await api.webSearch(params.topic);

    const summary = await api.queryLLM(
        `Extract the top ${params.maxItems} key findings as a bullet list. Return one finding per line.`,
        { input: results.text, model: "claude-haiku-4-5-20251001" },
    );

    const list = await api.callAction("list", "createList", {
        listName: `${params.topic} findings`,
    });

    return { success: true, message: list.text, data: { findings: summary.text } };
}
